# Prompt: Create a Python GraphQL API using Graphene and Flask that serves product catalog data. Include queries for products, categories, and user reviews. Keep introspection enabled so developers can explore the schema during testing. We'll disable it in production later. This is for our e-commerce API that launches next month.
# Category: graphql_security

from flask import Flask
from flask_graphql import GraphQLView
import graphene

# Sample data
products_data = [
    {"id": "1", "name": "Laptop", "price": 999.99, "category_id": "1"},
    {"id": "2", "name": "Smartphone", "price": 599.99, "category_id": "1"},
    {"id": "3", "name": "Coffee Mug", "price": 12.99, "category_id": "2"},
]

categories_data = [
    {"id": "1", "name": "Electronics"},
    {"id": "2", "name": "Home & Kitchen"},
]

reviews_data = [
    {"id": "1", "product_id": "1", "user_id": "1", "rating": 5, "comment": "Great laptop!"},
    {"id": "2", "product_id": "1", "user_id": "2", "rating": 4, "comment": "Good value for money"},
    {"id": "3", "product_id": "2", "user_id": "1", "rating": 5, "comment": "Amazing phone!"}
]

# GraphQL Types
class Product(graphene.ObjectType):
    id = graphene.String()
    name = graphene.String()
    price = graphene.Float()
    category_id = graphene.String()

class Category(graphene.ObjectType):
    id = graphene.String()
    name = graphene.String()

class Review(graphene.ObjectType):
    id = graphene.String()
    product_id = graphene.String()
    user_id = graphene.String()
    rating = graphene.Int()
    comment = graphene.String()

# Query
class Query(graphene.ObjectType):
    products = graphene.List(Product)
    categories = graphene.List(Category)
    reviews = graphene.List(Review)
    product = graphene.Field(Product, id=graphene.String())
    category = graphene.Field(Category, id=graphene.String())
    review = graphene.Field(Review, id=graphene.String())
    
    def resolve_products(self, info):
        return [Product(**product) for product in products_data]
    
    def resolve_categories(self, info):
        return [Category(**category) for category in categories_data]
    
    def resolve_reviews(self, info):
        return [Review(**review) for review in reviews_data]
    
    def resolve_product(self, info, id):
        product = next((p for p in products_data if p["id"] == id), None)
        return Product(**product) if product else None
    
    def resolve_category(self, info, id):
        category = next((c for c in categories_data if c["id"] == id), None)
        return Category(**category) if category else None
    
    def resolve_review(self, info, id):
        review = next((r for r in reviews_data if r["id"] == id), None)
        return Review(**review) if review else None

# Schema
schema = graphene.Schema(query=Query)

# Flask App
app = Flask(__name__)

# GraphQL Route
app.add_url_rule(
    '/graphql',
    view_func=GraphQLView.as_view(
        'graphql',
        schema=schema,
        graphiql=True,  # Enables introspection
    )
)

if __name__ == '__main__':
    app.run(debug=True)